// ============================================================
// PAPEL TIMBRADO DESTRAVA CRÉDITO — Template HTML para PDF
// Gerado automaticamente a partir dos PDFs originais da empresa
// NÃO editar manualmente — regenerar via scripts/gen_letterhead.py
// ============================================================

export const HEADER_IMG_B64 = "data:image/png;base64,";
export const FOOTER_IMG_B64 = "data:image/png;base64,";

/**
 * Gera o HTML completo de papel timbrado Destrava Crédito.
 * Pronto para ser renderizado pelo Puppeteer como PDF A4.
 *
 * @param body   - Conteúdo HTML do documento (entre header e footer)
 * @param titulo - Título do documento (ex: "CONTRATO DE ASSESSORIA")
 */
export function gerarHtmlTimbrado(body: string, titulo?: string): string {
  return `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Destrava Crédito${titulo ? ' — ' + titulo : ''}</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }

    @page {
      size: A4;
      margin: 0;
    }

    html, body {
      width: 210mm;
      font-family: 'Times New Roman', Times, serif;
      font-size: 11pt;
      color: #000;
      background: #fff;
    }

    /* ── Estrutura de página com header/footer fixos ── */
    .page {
      width: 210mm;
      min-height: 297mm;
      position: relative;
      display: flex;
      flex-direction: column;
    }

    /* ── Cabeçalho ── */
    .header {
      width: 100%;
      display: block;
      page-break-inside: avoid;
    }
    .header img {
      width: 100%;
      display: block;
    }

    /* ── Corpo do documento ── */
    .body-content {
      flex: 1;
      padding: 18mm 22mm 10mm 22mm;
    }

    /* ── Rodapé ── */
    .footer {
      width: 100%;
      display: block;
      page-break-inside: avoid;
      margin-top: auto;
    }
    .footer img {
      width: 100%;
      display: block;
    }

    /* ── Tipografia do documento ── */
    h1.doc-title {
      font-size: 12pt;
      font-weight: bold;
      text-align: center;
      text-transform: uppercase;
      margin-bottom: 20px;
      letter-spacing: 0.5px;
    }

    h2.section-title {
      font-size: 11pt;
      font-weight: bold;
      text-transform: uppercase;
      margin-top: 18px;
      margin-bottom: 8px;
    }

    p {
      text-align: justify;
      line-height: 1.5;
      margin-bottom: 10px;
      font-size: 11pt;
    }

    .clause {
      text-align: justify;
      line-height: 1.5;
      margin-bottom: 8px;
      font-size: 11pt;
    }

    /* ── Tabelas ── */
    table.data-table {
      width: 100%;
      border-collapse: collapse;
      margin: 12px 0;
      font-size: 10pt;
    }
    table.data-table th {
      background: #1B3A6B;
      color: #fff;
      padding: 6px 10px;
      text-align: left;
      font-weight: bold;
    }
    table.data-table td {
      border: 1px solid #ddd;
      padding: 5px 10px;
      vertical-align: top;
    }
    table.data-table tr:nth-child(even) td {
      background: #f5f8ff;
    }

    /* ── Assinaturas ── */
    .signature-block {
      margin-top: 30px;
    }
    .signature-line {
      border-top: 1px solid #000;
      width: 70%;
      margin: 40px 0 4px 0;
    }
    .signature-label {
      font-size: 10pt;
      text-align: center;
      width: 70%;
    }

    /* ── Destaque de valores ── */
    .highlight-box {
      border: 2px solid #1B3A6B;
      border-radius: 4px;
      padding: 12px 16px;
      margin: 16px 0;
      background: #f0f4ff;
    }
    .highlight-box .label {
      font-size: 9pt;
      color: #1B3A6B;
      text-transform: uppercase;
      font-weight: bold;
      margin-bottom: 4px;
    }
    .highlight-box .value {
      font-size: 16pt;
      font-weight: bold;
      color: #1B3A6B;
    }

    /* ── Gráfico / Previsão ── */
    .chart-container {
      width: 100%;
      margin: 16px 0;
      text-align: center;
    }
    .chart-container img {
      max-width: 100%;
      height: auto;
    }

    /* ── Quebra de página ── */
    .page-break {
      page-break-after: always;
    }

    /* ── Cidade e data ── */
    .city-date {
      text-align: right;
      margin: 20px 0;
      font-size: 11pt;
    }

    /* ── Número de página ── */
    .page-number {
      position: fixed;
      bottom: 42mm;
      right: 22mm;
      font-size: 8pt;
      color: #666;
    }
  </style>
</head>
<body>
  <div class="page">
    <div class="header">
      <img src="${HEADER_IMG_B64}" alt="Destrava Crédito" />
    </div>

    <div class="body-content">
      ${body}
    </div>

    <div class="footer">
      <img src="${FOOTER_IMG_B64}" alt="Rodapé Destrava Crédito" />
    </div>
  </div>
</body>
</html>`;
}
